SELECT MAX(auc_avg) AS max_auc_avg
FROM model_performance
WHERE auc_avg > 0.9;

SELECT e.experiment_name
FROM experiments e
JOIN model_performance mp ON e.experiment_id = mp.experiment_id
WHERE mp.f1_avg_best = (
  SELECT MAX(f1_avg_best) FROM model_performance
);

SELECT DISTINCT u.role
FROM experiments e
JOIN users u ON e.user_id = u.user_id;

SELECT MAX(f1_avg_best) AS peak_f1_score
FROM model_performance
WHERE user_id = 2;

SELECT AVG(f1_avg_best) AS avg_best_f1_score
FROM model_performance
WHERE user_id = 2 AND dataset_id = 2;

SELECT MAX(f1_avg_best) AS best_f1
FROM model_performance
WHERE user_id = 1 AND dataset_id = 1;

SELECT MAX(f1_avg_best) AS highest_f1_avg_best
FROM model_performance
WHERE dataset_id IN (1, 2);
